#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i) * matrix_dim + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        int tx;

        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx][i] -= shadow[tx][j] * shadow[j][i];
            }
            shadow[tx][i] /= shadow[i][i];
        }

        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[i + 1][tx] -= shadow[i + 1][j] * shadow[j][tx];
            }
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + offset + j] = shadow[i][j];
        }
    }
}

static void lud_perimeter_block(float *m, int matrix_dim, int offset, int block_id)
{
    int i, j;
    int global_col_block;
    int global_row_block;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    global_col_block = offset + (block_id + 1) * BLOCK_SIZE;
    global_row_block = offset + (block_id + 1) * BLOCK_SIZE;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[i][j] = m[(offset + i) * matrix_dim + offset + j];
            peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_block + j];
            peri_col[i][j] = m[(global_row_block + i) * matrix_dim + offset + j];
        }
    }

    for (j = 0; j < BLOCK_SIZE; j++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            int k;
            for (k = 0; k < i; k++) {
                peri_row[i][j] -= dia[i][k] * peri_row[k][j];
            }
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            int k;
            for (k = 0; k < j; k++) {
                peri_col[i][j] -= peri_col[i][k] * dia[k][j];
            }
            peri_col[i][j] /= dia[j][j];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + global_col_block + j] = peri_row[i][j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(global_row_block + i) * matrix_dim + offset + j] = peri_col[i][j];
        }
    }
}

static void lud_internal_block(float *m, int matrix_dim, int offset, int bx, int by)
{
    int i, j, k;
    int global_row_id;
    int global_col_id;
    float sum;
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    global_row_id = offset + (by + 1) * BLOCK_SIZE;
    global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_id + j];
            peri_col[i][j] = m[(global_row_id + i) * matrix_dim + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += peri_col[i][k] * peri_row[k][j];
            }
            m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i;
    for (i = 0; matrix_dim - BLOCK_SIZE > i; i += BLOCK_SIZE) {
        int num_blocks;
        int bx, by;

        lud_diagonal_omp(m, matrix_dim, i);

        num_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

#pragma omp parallel for private(bx) schedule(static) num_threads(omp_num_threads)
        for (bx = 0; bx < num_blocks; bx++) {
            lud_perimeter_block(m, matrix_dim, i, bx);
        }

#pragma omp parallel for collapse(2) private(by, bx) schedule(static) num_threads(omp_num_threads)
        for (by = 0; by < num_blocks; by++) {
            for (bx = 0; bx < num_blocks; bx++) {
                lud_internal_block(m, matrix_dim, i, bx, by);
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
